from abc import ABC, abstractmethod
from typing import List

class Command(ABC):
    """Command interface."""

    @abstractmethod
    def execute(self) -> None:
        pass

    @abstractmethod
    def undo(self) -> None:
        pass

class Receiver:
    """Contains business logic."""

    def do_something(self, a: str) -> None:
        print(f"Receiver: Working on ({a})")

    def do_something_else(self, b: str) -> None:
        print(f"Receiver: Also working on ({b})")

class SimpleCommand(Command):
    """Simple command with no receiver."""

    def __init__(self, payload: str):
        self._payload = payload

    def execute(self) -> None:
        print(f"SimpleCommand: {self._payload}")

    def undo(self) -> None:
        print(f"SimpleCommand: Undoing {self._payload}")

class ComplexCommand(Command):
    """Delegates to receiver."""

    def __init__(self, receiver: Receiver, a: str, b: str):
        self._receiver = receiver
        self._a = a
        self._b = b

    def execute(self) -> None:
        self._receiver.do_something(self._a)
        self._receiver.do_something_else(self._b)

    def undo(self) -> None:
        print(f"ComplexCommand: Undoing operations")

class Invoker:
    """Stores and executes commands."""

    def __init__(self):
        self._history: List[Command] = []

    def execute_command(self, command: Command) -> None:
        command.execute()
        self._history.append(command)

    def undo_last(self) -> None:
        if self._history:
            command = self._history.pop()
            command.undo()

